#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int cnt1=0,cnt0=0,x;
        for(int i=0;i<7;i++){
            scanf("%d",&x);
            if(x==1) cnt1++; else cnt0++;
        }
        if(cnt1>cnt0) printf("YES\n"); else printf("NO\n");
    }
    return 0;
}

