import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    idx = 1
    out = []
    for _ in range(t):
        cnt1 = cnt0 = 0
        for _ in range(7):
            val = int(data[idx]); idx += 1
            if val == 1:
                cnt1 += 1
            else:
                cnt0 += 1
        out.append('YES' if cnt1 > cnt0 else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == '__main__':
    main()

